def yaml_loader_function(yaml_path):
    with open(yaml_path, 'r') as f:
        config = yaml.safe_load(f)
    return {'config': config}

def utilities_function(system_data):
    raut = RAUtilities()
    raut_data = {}
    rasd_data = system_data
    (raut_data['mu_tot'], raut_data['lambda_tot']) = raut.reltrates(rasd_data['MTTF_gen'], rasd_data['MTTF_trans'], rasd_data['MTTR_gen'], rasd_data['MTTR_trans'], rasd_data['MTTF_ess'], rasd_data['MTTR_ess'])
    (raut_data['cap_max'], raut_data['cap_min']) = raut.capacities(rasd_data['nl'], rasd_data['pmax'], rasd_data['pmin'], rasd_data['ess_pmax'], rasd_data['ess_pmin'], rasd_data['cap_trans'])
    print('Utilities formed')
    return {'utility_data': raut_data}

def matrices_function(system_data):
    rasd = system_data
    ramat = RAMatrices(rasd['nz'])
    ramat_data = {}
    ramat_data['gen_mat'] = ramat.genmat(rasd['ng'], rasd['genbus'], rasd['ness'], rasd['essbus'])
    ramat_data['ch_mat'] = ramat.chmat(rasd['ness'], rasd['essbus'], rasd['nz'])
    ramat_data['A_inc'] = ramat.Ainc(rasd['nl'], rasd['fb'], rasd['tb'])
    ramat_data['curt_mat'] = ramat.curtmat(rasd['nz'])
    print('Matrices formed')
    return {'matrices': ramat_data}

def DataDownloader_function(yaml_path):
    data = DataProcess(yaml_path)
    data.ProcessWindData()
    data.ProcessSolarData()
    return {'output': 1}

def mcs_setup_function(config, system_data, utility_data, matrices, wind_data, solar_data):
    print('MCS module just started')
    progress_root = Path(progress.__file__).resolve().parent
    glpk_candidates = [progress_root.parent.parent.parent / 'glpk' / 'glpk-4.65' / 'w64', progress_root.parent.parent.parent / 'glpk' / 'GLPK-4.65' / 'w64', progress_root / 'glpk' / 'glpk-4.65' / 'w64', progress_root / 'glpk' / 'GLPK-4.65' / 'w64']
    for glpk_dir in glpk_candidates:
        glpsol = glpk_dir / 'glpsol.exe'
        if glpsol.exists():
            current_path = os.environ.get('PATH', '')
            glpk_str = str(glpk_dir)
            if glpk_str not in current_path.split(os.pathsep):
                os.environ['PATH'] = glpk_str + os.pathsep + current_path if current_path else glpk_str
            print(f'GLPK configured from {glpk_dir}')
            break
    else:
        print('Warning: glpsol.exe was not found in the expected Progress environment locations.')
    samples = config['samples']
    sim_hours = config['sim_hours']
    indices_rec = {'LOLP_rec': np.zeros(samples), 'EUE_rec': np.zeros(samples), 'MDT_rec': np.zeros(samples), 'LOLF_rec': np.zeros(samples), 'EPNS_rec': np.zeros(samples), 'LOLP_hr': np.zeros(sim_hours), 'LOLE_rec': np.zeros(samples), 'mLOLP_rec': np.zeros(samples), 'COV_rec': np.zeros(samples)}
    simulation_context = {'config': config, 'rasd': system_data, 'raut_data': utility_data, 'rmat': matrices, 'rwind': wind_data, 'rsolar': solar_data, 'samples': samples, 'sim_hours': sim_hours, 'indices_rec': indices_rec, 'LOL_track': np.zeros((samples, sim_hours))}
    print('MCS setup complete')
    return {'simulation_context': simulation_context}

def mcs_run_samples_function(simulation_context):
    config = simulation_context['config']
    rasd = simulation_context['rasd']
    raut_data = simulation_context['raut_data']
    rmat = simulation_context['rmat']
    rsolar = simulation_context['rsolar']
    rwind = simulation_context['rwind']
    samples = simulation_context['samples']
    sim_hours = simulation_context['sim_hours']
    indices_rec = simulation_context['indices_rec']
    LOL_track = simulation_context['LOL_track']
    raut = RAUtilities()
    print('Simulation started')
    results_subdir = None
    for s in range(samples):
        print(f'Sample: {s + 1}')
        var_s = {'t_min': 0, 'LLD': 0, 'curtailment': np.zeros(sim_hours), 'label_LOLF': np.zeros(sim_hours), 'freq_LOLF': 0, 'LOL_days': 0, 'outage_day': np.zeros(365)}
        current_state = np.ones(rasd['ng'] + rasd['nl'] + rasd['ness'])
        if rwind:
            current_w_class = np.floor(np.random.uniform(0, 1, rwind['w_sites']) * rwind['w_classes']).astype(int)
        renewable_rec = {'wind_rec': np.zeros((rasd['nz'], sim_hours)), 'solar_rec': np.zeros((rasd['nz'], sim_hours)), 'congen_temp': 0, 'rengen_temp': 0}
        SOC_old = 0.5 * np.multiply(np.multiply(rasd['ess_pmax'], rasd['ess_duration']), rasd['ess_socmax']) / rasd['BMva']
        SOC_rec = np.zeros((rasd['ness'], sim_hours))
        curt_rec = np.zeros(sim_hours)
        part_netload = config['load_factor'] * rasd['load_all_regions']
        for n in range(sim_hours):
            next_state, current_cap, var_s['t_min'] = raut.NextState(var_s['t_min'], rasd['ng'], rasd['ness'], rasd['nl'], raut_data['lambda_tot'], raut_data['mu_tot'], current_state, raut_data['cap_max'], raut_data['cap_min'], rasd['ess_units'])
            current_state = copy.deepcopy(next_state)
            ess_smax, ess_smin, SOC_old = raut.updateSOC(rasd['ng'], rasd['nl'], current_cap, rasd['ess_pmax'], rasd['ess_duration'], rasd['ess_socmax'], rasd['ess_socmin'], SOC_old)
            gt_limits = {'g_lb': np.concatenate((current_cap['min'][0:rasd['ng']] / rasd['BMva'], current_cap['min'][rasd['ng'] + rasd['nl']:] / rasd['BMva'])), 'g_ub': np.concatenate((current_cap['max'][0:rasd['ng']] / rasd['BMva'], current_cap['max'][rasd['ng'] + rasd['nl']:] / rasd['BMva'])), 'tl': current_cap['max'][rasd['ng']:rasd['ng'] + rasd['nl']] / rasd['BMva']}

            def fb_Pg(model, i):
                return (gt_limits['g_lb'][i], gt_limits['g_ub'][i])

            def fb_flow(model, i):
                return (-gt_limits['tl'][i], gt_limits['tl'][i])

            def fb_ess(model, i):
                return (-current_cap['max'][rasd['ng'] + rasd['nl']:][i] / rasd['BMva'], current_cap['min'][rasd['ng'] + rasd['nl']:][i] / rasd['BMva'])

            def fb_soc(model, i):
                return (ess_smin[i] / rasd['BMva'], ess_smax[i] / rasd['BMva'])
            if rwind:
                w_zones, current_w_class = raut.WindPower(rasd['nz'], rwind['w_sites'], rwind['zone_no'], rwind['w_classes'], rwind['r_cap'], current_w_class, rwind['tr_mats'], rwind['p_class'], rwind['w_turbines'], rwind['out_curve2'], rwind['out_curve3'])
            if rsolar:
                s_zones = raut.SolarPower(n, rasd['nz'], rsolar['s_zone_no'], rsolar['solar_prob'], rsolar['s_profiles'], rsolar['s_sites'], rsolar['s_max'])
            if rwind:
                renewable_rec['wind_rec'][:, n] = w_zones
            if rsolar:
                s_zones_t = np.transpose(s_zones)
                renewable_rec['solar_rec'][:, n] = s_zones_t[:, n % 24]
            if rsolar and rwind:
                net_load = part_netload[n] - w_zones - s_zones[n % 24]
            elif not rsolar and rwind:
                net_load = part_netload[n] - w_zones
            elif rsolar and (not rwind):
                net_load = part_netload[n] - s_zones[n % 24]
            else:
                net_load = part_netload[n]
            if config['model'] == 'Zonal':
                load_curt, SOC_old = raut.OptDispatch(rasd['ng'], rasd['nz'], rasd['nl'], rasd['ness'], fb_ess, fb_soc, rasd['BMva'], fb_Pg, fb_flow, rmat['A_inc'], rmat['gen_mat'], rmat['curt_mat'], rmat['ch_mat'], rasd['gencost'], net_load, SOC_old, rasd['ess_pmax'], rasd['ess_eff'], rasd['disch_cost'], rasd['ch_cost'])
            elif config['model'] == 'Copper Sheet':
                load_curt, SOC_old = raut.OptDispatchLite(rasd['ng'], rasd['nz'], rasd['ness'], fb_ess, fb_soc, rasd['BMva'], fb_Pg, rmat['A_inc'], rasd['gencost'], net_load, SOC_old, rasd['ess_pmax'], rasd['ess_eff'], rasd['disch_cost'], rasd['ch_cost'])
            SOC_rec[:, n] = SOC_old * rasd['BMva']
            curt_rec[n] = load_curt * rasd['BMva']
            var_s, LOL_track = raut.TrackLOLStates(load_curt, rasd['BMva'], var_s, LOL_track, s, n)
            if (n + 1) % 100 == 0:
                print(f'Hour {n + 1}')
        indices_rec = raut.UpdateIndexArrays(indices_rec, var_s, sim_hours, s)
        indices_rec['mLOLP_rec'][s] = np.mean(indices_rec['LOLP_rec'][0:s + 1])
        var_LOLP = np.var(indices_rec['LOLP_rec'][0:s + 1])
        if indices_rec['mLOLP_rec'][s] != 0:
            indices_rec['COV_rec'][s] = np.sqrt(var_LOLP) / indices_rec['mLOLP_rec'][s]
        else:
            indices_rec['COV_rec'][s] = 0
        if s == 0:
            main_folder = get_path()
            timestamp = datetime.now().strftime('%Y-%m-%d_%H-%M-%S')
            results_subdir = os.path.join(main_folder, 'Results', timestamp)
            os.makedirs(results_subdir, exist_ok=True)
        sample_subdir = os.path.join(results_subdir, f'Sample {s + 1}')
        os.makedirs(sample_subdir, exist_ok=True)
        rapt = RAPlotTools(sample_subdir)
        rapt.PlotSolarGen(renewable_rec['solar_rec'], rasd['bus_name'], s)
        rapt.PlotWindGen(renewable_rec['wind_rec'], rasd['bus_name'], s)
        rapt.PlotSOC(SOC_rec, rasd['essname'], s)
        rapt.PlotLoadCurt(curt_rec, s)
    return {'simulation_state': {'indices_rec': indices_rec, 'results_subdir': results_subdir, 'samples': samples, 'sim_hours': sim_hours, 'LOL_track': LOL_track}}
